public class TypeInference {
    public static <T> List<T> singletonList(T item) {
        List<T> list = new ArrayList<>();
        list.add(item);
        return list;
    }

    public static void main(String[] args) {
        // Type inference (usually written this way)
        List<String> list1 = singletonList("Hello");

        // Explicitly specifying the type
        List<String> list2 = TypeInference.<String>singletonList("Hello");

        // Explicit specification may be needed when type inference is ambiguous
        List<Object> list3 = TypeInference.<Object>singletonList(null);
    }
}

public class Container<T> {
    private T value;

    // OK: Instance methods can use the class type parameter T
    public T getValue() {
        return value;
