// Generic method restricted to Number and its subtypes
public static <T extends Number> double sum(List<T> list) {
    double total = 0.0;
    for (T element : list) {
        total += element.doubleValue();  // Can call Number's methods
    }
    return total;
}

// Usage example
List<Integer> intList = List.of(1, 2, 3);
double result1 = sum(intList);  // OK: Integer is a subclass of Number

List<Double> dblList = List.of(1.5, 2.5);
double result2 = sum(dblList);  // OK: Double is a subclass of Number

// List<String> strList = List.of("a");
// sum(strList);  // Compile error: String is not a subclass of Number

// Restricted to types implementing both Comparable and Serializable
public static <T extends Comparable<T> & Serializable> T findMax(List<T> list) {
    T max = list.get(0);
    for (T item : list) {
        if (item.compareTo(max) > 0) {
            max = item;
        }
    }
    return max;
}

// When mixing class + interface, the class comes first
// <T extends Number & Comparable<T>>  // OK
// <T extends Comparable<T> & Number>  // Compile error (class comes after)

// Example of recursive type bound
public class SortUtil {
    // Guarantees that T implements Comparable<T>
    public static <T extends Comparable<T>> T max(T a, T b) {
        return a.compareTo(b) >= 0 ? a : b;
    }

    public static void main(String[] args) {
        String result = max("Apple", "Banana");  // "Banana"
        Integer num = max(10, 20);  // 20
    }
}

