public class Restrictions<T> {
    // Compile error: Primitive types are not allowed
    // Box<int> box;

    // Compile error: new T() is not allowed
    // public T create() { return new T(); }

    // Compile error: Creating generic arrays is not allowed
    // T[] array = new T[10];

    // Compile error: instanceof with parameterized types is not allowed
    // if (obj instanceof List<String>) { }

    // OK: instanceof with unbounded wildcard is allowed
    public boolean isList(Object obj) {
        return obj instanceof List<?>;
    }

    // OK: instanceof with raw type is also allowed
    public boolean isListRaw(Object obj) {
        return obj instanceof List;
    }
}

public class OverloadExample {
    // Compile error: Same signature after type erasure
    // public void process(List<String> list) { }
    // public void process(List<Integer> list) { }

    // After type erasure, both become the same:
    // public void process(List list) { }

    // Solution: Use different method names
    public void processStrings(List<String> list) { }
    public void processIntegers(List<Integer> list) { }
}

// Example using type tokens
public class TypeSafeMap {
    private Map<Class<?>, Object> map = new HashMap<>();

    public <T> void put(Class<T> type, T value) {
        map.put(type, value);
    }

    public <T> T get(Class<T> type) {
        return type.cast(map.get(type));
    }
}

// Usage example
TypeSafeMap tsm = new TypeSafeMap();
tsm.put(String.class, "Hello");
tsm.put(Integer.class, 42);
String s = tsm.get(String.class);  // No cast needed

